INSERT INTO `t_article` VALUES (1, 'Spring Boot 3.0 新特性详解', 'Spring Boot 3.0 带来了许多令人兴奋的新特性，本文将详细介绍这些变化...', '# Spring Boot 3.0 新特性详解\n\nSpring Boot 3.0 是一个重要的里程碑版本，带来了许多重大更新。\n\n## 1. 最低要求 Java 17\n\nSpring Boot 3.0 要求最低使用 Java 17...\n\n## 2. Jakarta EE 支持\n\n从 javax 迁移到 jakarta 命名空间...\n\n## 3. 原生编译支持\n\n支持 GraalVM 原生编译...', NULL, 1, 1, 105, 0, '2026-03-22 11:02:32', '2026-03-22 16:33:42', 1);
INSERT INTO `t_article` VALUES (2, 'MySQL 8.0 性能优化实践', '分享 MySQL 8.0 在实际项目中的性能优化经验...', '# MySQL 8.0 性能优化实践\n\n本文分享一些 MySQL 8.0 的性能优化技巧。\n\n## 索引优化\n\n合理的索引设计是性能优化的关键...\n\n## 查询优化\n\n避免全表扫描，使用 EXPLAIN 分析执行计划...', NULL, 1, 1, 83, 0, '2026-03-22 11:02:32', '2026-03-22 16:33:40', 1);
INSERT INTO `t_article` VALUES (3, '我的2024年学习计划', '新的一年，新的开始，记录一下我的学习计划...', '# 我的2024年学习计划\n\n新的一年，给自己定下几个目标：\n\n1. 深入学习 Java 并发编程\n2. 掌握微服务架构设计\n3. 学习 Kubernetes\n4. 多写技术博客\n\n加油！', NULL, 2, 1, 53, 0, '2026-03-22 11:02:32', '2026-03-22 16:33:39', 1);
INSERT INTO `t_article` VALUES (4, 'MCP：AI 世界的 USB 协议', NULL, '\n\n**MCP：AI 世界的 USB 协议**\n\n还记得十年前的充电线吗？苹果用 Lightning，安卓用 Micro USB，笔记本用各种奇形怪状的电源头。出门一趟，包里塞满五六根线。\n\nAI 行业在 2024 年之前也是这样。\n\n你想让 Agent 读取 GitHub 仓库？写一套对接代码。想让 ChatGPT 查数据库？再写一套。想让 Cursor 发 Slack 消息？又是一套。10 个 AI 应用要连 20 个工具，理论上需要 200 个定制集成。每家都在重复造轮子，开发者苦不堪言。\n\n2024 年 11 月，Anthropic 开源了 MCP（Model Context Protocol，模型上下文协议）。它做的事情，和 USB-C 统一充电接口一模一样：**定义一套标准协议，让任何 AI 都能即插即用地连接任何工具。**\n\n有了 MCP，10 个 AI 应用 + 20 个工具 = 30 个 MCP 实现，而不是 200 个定制集成。数学上叫把 M×N 问题变成了 M+N 问题，实践中意味着开发成本断崖式下降。\n\n**致命问题：上下文爆炸**\n\nMCP 有一个严重的副作用：**吃掉你的上下文窗口**。\n\n每个 MCP Server 连接到 AI 时，必须把所有工具的定义（名称、描述、参数、示例）一次性塞进上下文。一个工具的定义大概 500-800 tokens，一个 MCP Server 通常有 10-20 个工具。\n\n**Claude Code 的解法：Tool Search**\n\nAnthropic 意识到了这个问题。2025 年 1 月，Claude Code 推出了 **Tool Search** 功能：\n\n-   • MCP 工具不再预加载，而是**按需发现**\n-   • 当工具定义超过上下文的 10% 时自动启用\n-   • AI 需要用某个工具时，先搜索再加载', NULL, 1, NULL, 2, 1, '2026-03-22 16:23:03', '2026-03-22 16:40:02', 0);
